
.cy-info {
  display: flex;
  justify-content: center;
  gap: 28px;
  font-size: 11px;
  letter-spacing: .5px;
  color: var(--c-text-mute);
  padding: 8px 0 4px;
  border-bottom: 1px solid var(--c-border);
}
.cy-info-cell {
  display: flex;
  gap: 4px;
  align-items: baseline;
}
.cy-info-cell b {
  color: var(--c-blue-deep);
  font-weight: normal;
  flex: none;
}
.cy-info-cell i {
  font-style: normal;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  max-width: 140px;
}
@media (max-width: 520px) {
  .cy-info {
    gap: 8px;
    font-size: 9px;
  }
  .cy-info-cell {
    gap: 1px;
  }
  .cy-info-cell i {
    max-width: 70px;
  }
}
